import{_ as e,a as t,b as i}from"./chunks/支持留言.NiGCLVdp.js";import{_ as s,o as l,c as p,a2 as o}from"./chunks/framework.DnrXFDHb.js";const _=JSON.parse('{"title":"博客使用说明","description":"","frontmatter":{},"headers":[],"relativePath":"cn/Other/blog.md","filePath":"cn/Other/blog.md","lastUpdated":1781962217000}'),n={name:"cn/Other/blog.md"};function d(c,a,r,h,g,b){return l(),p("div",null,[...a[0]||(a[0]=[o('<h1 id="博客使用说明" tabindex="-1">博客使用说明 <a class="header-anchor" href="#博客使用说明" aria-label="Permalink to &quot;博客使用说明&quot;">​</a></h1><p>博客功能可以给你的图床站点增加一个独立博客页面。</p><p>开启后，访客可以通过：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://你的域名/blog/</span></span></code></pre></div><p>访问博客。</p><p><img src="'+e+'" alt="博客首页" loading="lazy"></p><p>博客页面基于 <a href="https://github.com/LyraVoid/Mizuki" target="_blank" rel="noreferrer">LyraVoid/Mizuki</a> 开源博客网站改造而来。感谢原项目的开源，我们使用 Vue 重写并适配到当前图床项目里。</p><h2 id="入口位置" tabindex="-1">入口位置 <a class="header-anchor" href="#入口位置" aria-label="Permalink to &quot;入口位置&quot;">​</a></h2><p>博客设置在：</p><p>系统配置 -&gt; 其他设置 -&gt; 博客</p><p><img src="'+t+'" alt="博客设置" loading="lazy"></p><h2 id="第一次使用" tabindex="-1">第一次使用 <a class="header-anchor" href="#第一次使用" aria-label="Permalink to &quot;第一次使用&quot;">​</a></h2><ol><li>打开“启用”开关。</li><li>选择用于保存博客配置的 GitHub 账号。</li><li>点击“更新博客”。</li><li>等系统提示博客更新成功。</li><li>访问 <code>https://你的域名/blog/</code> 查看博客。</li></ol><p>如果是第一次使用，系统会在你选择的 GitHub 账号下准备一个私有仓库：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>imgbed-blog-config</span></span></code></pre></div><p>这个仓库用于保存博客配置和文章内容。</p><h2 id="怎么写文章" tabindex="-1">怎么写文章 <a class="header-anchor" href="#怎么写文章" aria-label="Permalink to &quot;怎么写文章&quot;">​</a></h2><p>博客文章在你自己的 GitHub 私有仓库里修改：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>imgbed-blog-config</span></span></code></pre></div><p>常见做法是：</p><ol><li>打开自己的 GitHub。</li><li>进入 <code>imgbed-blog-config</code> 私有仓库。</li><li>修改或新增文章文件。</li><li>保存提交。</li><li>回到图床后台，点击“更新博客”刷新博客内容或者到博客首页左上角logo点击三次触发更新博客。</li></ol><p>“更新博客”不会覆盖你已经写好的内容，它主要用于初始化仓库或刷新博客缓存。</p><h2 id="支持的功能" tabindex="-1">支持的功能 <a class="header-anchor" href="#支持的功能" aria-label="Permalink to &quot;支持的功能&quot;">​</a></h2><p>博客支持文章列表、分类、标签、归档、搜索、深色模式、多语言切换等常见博客功能。</p><p>也支持留言和访问统计。</p><p><img src="'+i+'" alt="博客留言" loading="lazy"></p><p>留言会显示在文章页面下方。访客可以填写头像、昵称、邮箱和评论内容后提交。</p><p>访问统计会显示文章访问量、站点访问次数等信息，方便你了解博客的浏览情况。</p><h2 id="访问地址" tabindex="-1">访问地址 <a class="header-anchor" href="#访问地址" aria-label="Permalink to &quot;访问地址&quot;">​</a></h2><p>博客固定在 <code>/blog/</code> 路径下。</p><p>例如你的图床域名是：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://image.example.com</span></span></code></pre></div><p>博客地址就是：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://image.example.com/blog/</span></span></code></pre></div><p>关闭博客后，访客将无法访问博客页面。</p>',35)])])}const v=s(n,[["render",d]]);export{_ as __pageData,v as default};
